record.field:
services:
  litellm:
    image: ghcr.io/berriai/litellm:main-latest
    restart: unless-stopped
    depends_on:
      litellm-db:
        condition: service_healthy
    environment:
      DATABASE_URL: {{ database_url }}
      LITELLM_MASTER_KEY: {{ litellm_master_key }}
      UI_USERNAME: {{ ui_username }}
      UI_PASSWORD: {{ ui_password }}
      STORE_MODEL_IN_DB: 'True'
      OPENAI_API_KEY: {{ openai_api_key }}
      OPENAI_BASE_URL: {{ openai_base_url }}
      COHERE_API_KEY: {{ cohere_api_key }}
      OR_SITE_URL: {{ or_site_url }}
      OR_APP_NAME: {{ or_app_name }}
      OR_API_KEY: {{ or_api_key }}
      AZURE_API_BASE: {{ azure_api_base }}
      AZURE_API_VERSION: {{ azure_api_version }}
      AZURE_API_KEY: {{ azure_api_key }}
      REPLICATE_API_KEY: {{ replicate_api_key }}
      REPLICATE_API_TOKEN: {{ replicate_api_token }}
      ANTHROPIC_API_KEY: {{ anthropic_api_key }}
      INFISICAL_TOKEN: {{ infisical_token }}
      NOVITA_API_KEY: {{ novita_api_key }}
      INFINITY_API_KEY: {{ infinity_api_key }}
    expose:
    - 4000
    container_name: '{{ INSTANCE_CODE }}'
    ports:
    - '{{ PORT_HTTP }}:4000'
    networks:
    - internal
    - agz-proxy-network
  litellm-db:
    image: postgres:16-alpine
    restart: on-failure:5
    healthcheck:
      test:
      - CMD-SHELL
      - pg_isready -U {{ postgres_user }} -d {{ postgres_db }}
      interval: 5s
      timeout: 5s
      retries: 5
    volumes:
    - ./litellm_db:/var/lib/postgresql/data
    environment:
      POSTGRES_DB: {{ postgres_db }}
      POSTGRES_USER: {{ postgres_user }}
      POSTGRES_PASSWORD: {{ postgres_password }}
    container_name: '{{ INSTANCE_CODE }}_litellm_db'
    networks:
    - internal
networks:
  internal:
    driver: bridge
  agz-proxy-network:
    external: true
